"""Block Brawl Audio → MIDI Converter
Converts the game's Web Audio API track data into a multi-track MIDI file.
"""
import math, os
from midiutil import MIDIFile

BPM = 140
LOOP_SECS = 13.7143

def freq_to_midi(freq):
    if freq <= 0: return 60
    return max(0, min(127, round(69 + 12 * math.log2(freq / 440.0))))

def gain_to_vel(gain, scale=1.0):
    return max(1, min(127, round(gain * scale * 127)))

def secs_to_beats(secs):
    return secs * BPM / 60.0

