# ═══════════════════════════════════════════
# BUILD MIDI
# ═══════════════════════════════════════════
# 5 tracks: Jurassic, Medieval, City, Space, Drums
midi = MIDIFile(5, deinterleave=False)
midi.addTempo(0, 0, BPM)

# Track 0: Jurassic — GM 82 (Sawtooth Lead, 1-indexed)
TR_JUR, CH_JUR = 0, 0
midi.addTrackName(TR_JUR, 0, "Jurassic (Sawtooth Bass)")
midi.addProgramChange(TR_JUR, CH_JUR, 0, 81)  # 0-indexed = GM 82
for t, f, d, g in jurassic_raw:
    midi.addNote(TR_JUR, CH_JUR, freq_to_midi(f), secs_to_beats(t), secs_to_beats(d), gain_to_vel(g, 2.5))

# Track 1: Medieval — GM 81 (Square Lead)
TR_MED, CH_MED = 1, 1
midi.addTrackName(TR_MED, 0, "Medieval (Square Chords)")
midi.addProgramChange(TR_MED, CH_MED, 0, 80)
for t, f, d, g in medieval_raw:
    midi.addNote(TR_MED, CH_MED, freq_to_midi(f), secs_to_beats(t), secs_to_beats(d), gain_to_vel(g, 3.5))

# Track 2: City — GM 89 (Warm Pad)
TR_CITY, CH_CITY = 2, 2
midi.addTrackName(TR_CITY, 0, "City (Triangle Pad)")
midi.addProgramChange(TR_CITY, CH_CITY, 0, 88)
for t, f, d, g in city_raw:
    midi.addNote(TR_CITY, CH_CITY, freq_to_midi(f), secs_to_beats(t), secs_to_beats(d), gain_to_vel(g, 3.0))

# Track 3: Space — GM 99 (Atmosphere)
TR_SPC, CH_SPC = 3, 3
midi.addTrackName(TR_SPC, 0, "Space (Arpeggios)")
midi.addProgramChange(TR_SPC, CH_SPC, 0, 98)
for t, f, d, g in space_raw:
    dur = max(secs_to_beats(d), 0.01)
    midi.addNote(TR_SPC, CH_SPC, freq_to_midi(f), secs_to_beats(t), dur, gain_to_vel(g, 3.0))

# Track 4: Drums — Channel 9 (GM Percussion)
TR_DRM, CH_DRM = 4, 9
midi.addTrackName(TR_DRM, 0, "Drums")
drum_map = {'kick': 36, 'snare': 38, 'hat': 42, 'open': 46, 'ghost': 38}
for t, dtype, g in drums_raw:
    note = drum_map[dtype]
    vel = gain_to_vel(g, 1.0)
    if dtype == 'ghost':
        vel = max(1, min(vel, 40))  # keep ghosts soft
    midi.addNote(TR_DRM, CH_DRM, note, secs_to_beats(t), secs_to_beats(0.05), vel)

# ═══════════════════════════════════════════
# WRITE FILE
